export const geofences: Geofence[] = rawPolygonCoordinates.map((coords, index) => {
  const zoneInfo = zoneData[index] || { name: 'Zone ' + (index + 1), type: 'customer' as const };
  return {
    id: 'zone-' + (index + 1),
    name: zoneInfo.name,
    type: zoneInfo.type,
    color: ZONE_COLORS[zoneInfo.type],
    coordinates: coords,
    description: 'Geofence ' + zoneInfo.name,
    visible: true,
  };
});
